.verb-widget .milo-tooltip::before {
  content: attr(data-tooltip);
  position: absolute;
  top: 50%;
  transform: translateY(-50%);
  left: 100%;
  margin-left: 7px;
  max-width: 140px;
  padding: 10px;
  border-radius: 5px;
  background: #0469E3;
  color: #fff;
  text-align: left;
  display: none;
  z-index: 8;
  font-size: 12px;
  font-style: normal;
  font-weight: 400;
  line-height: 16px;
  width: max-content;
}

.verb-widget .milo-tooltip::after {
  content: "";
  position: absolute;
  left: 100%;
  margin-left: -8px;
  top: 50%;
  transform: translateY(-50%);
  border: 8px solid #0469E3;
  border-color: transparent #0469E3 transparent transparent;
  display: none;
  z-index: 8;
}

.verb-widget .milo-tooltip.top::before {
  left: 50%;
  transform: translateX(-50%) translateY(-100%);
  top: -6px;
  margin-bottom: 15px;
  margin-left: 0;
}

.verb-widget .milo-tooltip.top::after {
  left: 50%;
  top: 2px;
  transform: translateX(-50%) translateY(-50%);
  border: 8px solid #0469E3;
  border-color: #0469E3 transparent transparent;
  margin-left: 0;
}

.verb-widget .milo-tooltip:hover::before,
.verb-widget .milo-tooltip:focus::before,
.verb-widget .milo-tooltip:active::before {
  display: block; 
}

.verb-widget .milo-tooltip:hover::after,
.verb-widget .milo-tooltip:focus::after,
.verb-widget .milo-tooltip:active::after {
  display: block;
}

@supports (-webkit-backdrop-filter: blur(1px)) and (not (backdrop-filter: blur(1px))) {
  .verb-widget .milo-tooltip:focus::before {
    outline: 4px solid -webkit-focus-ring-color;
    outline-offset: 1px;
  }
}

@media screen and (max-width: 1199px) {
  .verb-widget .mobile.milo-tooltip.top::before {
    left: 0;
    right: auto;
    transform: translateX(0) translateY(-100%);
    max-width: 200px;
  }

  .verb-widget .mobile.milo-tooltip.top::after {
    left: 4px;
    right: auto;
    transform: translateX(0) translateY(-50%);
  }

  .verb-widget .tablet.milo-tooltip.top::before,
  .verb-widget .milo-tooltip.top::before {
    left: auto;
    right: 0;
    transform: translateX(0) translateY(-100%);
    max-width: 200px;
  }

  .verb-widget .tablet.milo-tooltip.top::after,
  .verb-widget .milo-tooltip.top::after {
    left: auto;
    right: 4px;
    transform: translateX(0) translateY(-50%);
  }

  [dir="rtl"] .verb-widget .mobile.milo-tooltip.top::before,
  [dir="rtl"] .verb-widget .tablet.milo-tooltip.top::before {
    transform: translateX(0) translateY(-100%);
    text-align: right;
  }

  [dir="rtl"] .verb-widget .mobile.milo-tooltip.top::before {
    left: auto;
    right: 0;
  }

  [dir="rtl"] .verb-widget .mobile.milo-tooltip.top::after,
  [dir="rtl"] .verb-widget .tablet.milo-tooltip.top::after {
    transform: translateX(0) translateY(-50%);
  }

  [dir="rtl"] .verb-widget .mobile.milo-tooltip.top::after {
    left: auto;
    right: 4px;
  }

  [dir="rtl"] .verb-widget .tablet.milo-tooltip.top::before {
    left: 0;
    right: auto;
  }

  [dir="rtl"] .verb-widget .tablet.milo-tooltip.top::after {
    left: 4px;
    right: auto;
  }
}

@media screen and (min-width: 1200px) {
  .verb-widget .milo-tooltip.top::before {
    max-width: 180px;
  }
}

</style><style>#prerender_verb-widget { position: absolute; top: 0; left: 0; width: 100%; z-index: -1; pointer-events: auto; }</style><meta property="og:locale" content="en-US"><link rel="preload" as="script" crossorigin="anonymous" href="/libs/martech/helpers.js"><link rel="preload" as="script" crossorigin="anonymous" href="/acrobat/blocks/verb-widget/verb-widget.js"><link rel="stylesheet" href="/acrobat/blocks/verb-widget/verb-widget.css"><link rel="preload" as="script" crossorigin="anonymous" href="/acrobat/blocks/unity/unity.js"><link rel="stylesheet" href="/acrobat/blocks/unity/unity.css"><link rel="stylesheet" href="/libs/blocks/global-navigation/global-navigation.css"><link rel="stylesheet" href="https://use.typekit.net/hah7vzn.css"><link rel="stylesheet" href="/libs/blocks/text/text.css"><link rel="stylesheet" href="/libs/blocks/section-metadata/section-metadata.css"><link rel="preload" as="script" href="/marketingtech/d4d114c60e50/a0e989131fd5/launch-5dd5dd2177e6.min.js"><link rel="stylesheet" href="/libs/blocks/global-navigation/base.css"><link rel="preload" as="script" crossorigin="anonymous" href="/libs/blocks/modal/modal.js"><link rel="stylesheet" href="/libs/blocks/modal/modal.css"><link rel="stylesheet" href="/libs/blocks/how-to/how-to.css"><link rel="stylesheet" href="/libs/styles/consonant-play-button.css"><script type="application/ld+json">{"@context":"http://schema.org","@type":"HowTo","name":"How to merge PDF files online","description":"With the merge PDF tool from Adobe Acrobat, you can combine multiple PDF documents into one file for free online. Now it’s easy to merge separate PDFs, organize pages in your document, and create a single, shareable PDF without installing software.Learn how to combine multiple PDF files into one with these easy steps:","publisher":{"@type":"Organization","name":"Adobe","logo":{"@type":"ImageObject","url":"content/dam/cc/icons/Adobe_Corporate_Horizontal_Red_HEX.svg"}},"step":[{"@type":"HowToStep","url":"/acrobat/online/merge-pdf/","name":"Step 1","itemListElement":[{"@type":"HowToDirection","text":"Click the Select files button above, or drag and drop files into the drop zone."}]},{"@type":"HowToStep","url":"/acrobat/online/merge-pdf/","name":"Step 2","itemListElement":[{"@type":"HowToDirection","text":"Select the files you want to merge using the Acrobat PDF combiner tool."}]},{"@type":"HowToStep","url":"/acrobat/online/merge-pdf/","name":"Step 3","itemListElement":[{"@type":"HowToDirection","text":"Reorder the files if needed."}]},{"@type":"HowToStep","url":"/acrobat/online/merge-pdf/","name":"Step 4","itemListElement":[{"@type":"HowToDirection","text":"Click Merge files."}]},{"@type":"HowToStep","url":"/acrobat/online/merge-pdf/","name":"Step 5","itemListElement":[{"@type":"HowToDirection","text":"Download your merged file or sign in to share it with a link."}]}],"@image":{"@type":"ImageObject","url":"acrobat/online/media_1ae354d8b7b963af98bab4a16e677e185a54545aa.png?width=750&format=png&optimize=medium"}}</script><link rel="stylesheet" href="/libs/blocks/icon-block/icon-block.css"><link rel="stylesheet" href="/libs/blocks/editorial-card/editorial-card.css"><link rel="stylesheet" href="/libs/blocks/accordion/accordion.css"><script type="application/ld+json">{"@context":"https://schema.org","@type":"FAQPage","mainEntity":[[{"@type":"Question","name":"\n            In what order will my merged PDF files appear?\n          ","acceptedAnswer":{"text":"Once you add the files you’d like to combine, you can drag and drop them into your preferred order. The top file in your list will appear first in the merged PDF file.","@type":"Answer"}},{"@type":"Question","name":"\n            How many pages can I include in a merged PDF?\n          ","acceptedAnswer":{"text":"The Acrobat Merge PDFs tool lets you create a merged, single PDF document of up to 1,500 pages. You can combine up to 100 files, with each individual file limited to 500 pages.","@type":"Answer"}},{"@type":"Question","name":"\n            Can I delete and reorder pages after I merge files?\n          ","acceptedAnswer":{"text":"When you combine PDF files, you can reorder, add, or delete files before you merge them into a single document. Sign in if you need to reorganize individual pages in your merged PDF. You can add, delete, move, or rotate PDF pages as needed until your content is in the desired order.","@type":"Answer"}},{"@type":"Question","name":"\n            Will the formatting of my merged documents be preserved?\n          ","acceptedAnswer":{"text":"Yes. One of the key benefits of using PDF format is that it maintains the original formatting, fonts, and layout across devices and platforms.","@type":"Answer"}},{"@type":"Question","name":"\n            Can I merge password-protected PDFs?\n          ","acceptedAnswer":{"text":"You can, but you’ll need to enter the password for each protected file before merging. Files without the correct password will not be included.","@type":"Answer"}},{"@type":"Question","name":"\n            Is it possible to merge PDFs with other file types?\n          ","acceptedAnswer":{"text":"Yes, when you start a 7-day free trial of Acrobat Pro you can combine PDFs with Word, Excel, PowerPoint, image files, and more. All files are converted into sequential pages within a single PDF. If you are not using Acrobat Pro, you can convert all of your files to PDFs to use Acrobat online tools for free.","@type":"Answer"}},{"@type":"Question","name":"\n            What is the best tool to merge PDFs?\n          ","acceptedAnswer":{"text":"Adobe Acrobat merge PDF tool is an online tool that helps you merge PDF files quickly and securely without needing to install any software, making it one of the best online tools to merge and combine PDFs.","@type":"Answer"}},{"@type":"Question","name":"\n            Is there a free tool to merge PDFs?\n          ","acceptedAnswer":{"text":"Yes, Adobe Acrobat merge PDF tool allows you to combine PDFs for free online.","@type":"Answer"}},{"@type":"Question","name":"\n            How do I put documents into a single file?\n          ","acceptedAnswer":{"text":"To put documents into a single file, use the Adobe Acrobat merge PDF tool above. Upload your PDF files, arrange them in the order you want, and merge them into one combined PDF that you can download and share.","@type":"Answer"}}]]}</script><link rel="stylesheet" href="/libs/blocks/caas/caas.css"><script type="application/ld+json">{"@context":"https://schema.org","@type":"BreadcrumbList","itemListElement":[{"@type":"ListItem","position":1,"name":"Home","item":"https://www.adobe.com/"},{"@type":"ListItem","position":2,"name":"Acrobat","item":"/acrobat/"},{"@type":"ListItem","position":3,"name":"Merge PDF","item":"/acrobat/online/merge-pdf/"}]}</script><link rel="stylesheet" href="https://prod.adobeccstatic.com/unav/1.5/UniversalNav.css"><link rel="stylesheet" href="/libs/blocks/media/media.css"><link rel="stylesheet" href="/acrobat/blocks/rnr/rnr.css"><link rel="stylesheet" type="text/css" href="https://prod.adobeccstatic.com/unav/1.5/layout.bundle.css"><link rel="stylesheet" type="text/css" href="https://prod.adobeccstatic.com/unav/1.5/popover.bundle.css"><link rel="stylesheet" type="text/css" href="https://prod.adobeccstatic.com/unav/1.5/profile.bundle.css"><script type="application/ld+json">{"name":"Merge PDFs","description":"Merge PDFs online for free. Combine PDF files to share information in a single file when you try Adobe Acrobat online services","@type":"Product","@context":"http://schema.org","aggregateRating":{"@type":"AggregateRating","ratingValue":"4.78","ratingCount":"307881"}}</script><link rel="stylesheet" href="/libs/blocks/columns/columns.css"><link rel="stylesheet" href="/libs/blocks/global-footer/global-footer.css"><link rel="stylesheet" href="/libs/blocks/global-navigation/utilities/menu/menu.css"><script type="application/ld+json" class="seotech-video-url">{"@context":"http://schema.org","@type":"VideoObj